from typing import Optional, Dict, Any
import json
import os


@dataclass
class ModelConfig:
    api_endpoint: str
    api_key: str
    model_name: str = "qwen-max"
    temperature: float = 0.7
    max_tokens: int = 2048
    timeout: int = 30
    max_retries: int = 3
    stream: bool = True
    extra_params: Optional[Dict[str, Any]] = None

    def to_dict(self) -> Dict[str, Any]:
        config = {
            "api_endpoint": self.api_endpoint,
            "api_key": self.api_key,
            "model_name": self.model_name,
            "temperature": self.temperature,
            "max_tokens": self.max_tokens,
            "timeout": self.timeout,
            "max_retries": self.max_retries,
            "stream": self.stream,
        }
        if self.extra_params:
            config.update(self.extra_params)
        return config


class ModelConfigLoader:
    def __init__(self, config_path: Optional[str] = None):
        self.config_path = config_path or os.environ.get(
            "LLM_CONFIG_PATH", "config/model_config.json"
        )

    def load_from_file(self) -> ModelConfig:
        if not os.path.exists(self.config_path):
            raise FileNotFoundError(f"配置文件不存在：{self.config_path}")

        with open(self.config_path, "r", encoding="utf-8") as f:
            config_data = json.load(f)

        return ModelConfig(**config_data)

    def load_from_env(self) -> ModelConfig:
        required_vars = ["LLM_API_ENDPOINT", "LLM_API_KEY"]
        for var in required_vars:
            if var not in os.environ:
                raise EnvironmentError(f"环境变量 {var} 未设置")

        return ModelConfig(
            api_endpoint=os.environ["LLM_API_ENDPOINT"],
            api_key=os.environ["LLM_API_KEY"],
            model_name=os.environ.get("LLM_MODEL_NAME", "qwen-max"),
            temperature=float(os.environ.get("LLM_TEMPERATURE", "0.7")),
            max_tokens=int(os.environ.get("LLM_MAX_TOKENS", "2048")),
            timeout=int(os.environ.get("LLM_TIMEOUT", "30")),
            max_retries=int(os.environ.get("LLM_MAX_RETRIES", "3")),
            stream=os.environ.get("LLM_STREAM", "true").lower() == "true",
        )

    def load_from_dict(self, config_dict: Dict[str, Any]) -> ModelConfig:
        return ModelConfig(**config_dict)

    def load(
        self, source: str = "auto", config_dict: Optional[Dict[str, Any]] = None
    ) -> ModelConfig:
        if source == "file" or (source == "auto" and os.path.exists(self.config_path)):
            return self.load_from_file()
        elif source == "env" or (source == "auto" and config_dict is None):
            return self.load_from_env()
        elif source == "dict" or config_dict is not None:
            if config_dict is None:
                raise ValueError("config_dict 不能为空")
            return self.load_from_dict(config_dict)
        else:
            raise ValueError(f"未知的配置来源：{source}")


def get_model_config(
    source: str = "auto", config_dict: Optional[Dict[str, Any]] = None
) -> ModelConfig:
    loader = ModelConfigLoader()
    return loader.load(source=source, config_dict=config_dict)
"}

