from typing import Any, Dict, Optional, Generator
import requests
import json
import time
from datetime import datetime

import sys
import os

sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.dirname(__file__))))
from services.model_config import ModelConfig


class BaseOutputService(ABC):
    def __init__(self):
        self.name = "BaseOutputService"

    @abstractmethod
    def output(self, data: Any) -> None:
        pass

    def __str__(self) -> str:
        return self.name


class ConsoleOutputService(BaseOutputService):
    def __init__(self):
        super().__init__()
        self.name = "ConsoleOutputService"

    def output(self, data: Any) -> None:
        print(f"[{self.name}] {datetime.now().isoformat()} - {data}")


class BaseIORecorder(ABC):
    def __init__(self):
        self.name = "BaseIORecorder"
        self.records = []

    @abstractmethod
    def record(self, input_data: Any, output_data: Any, metadata: Optional[Dict] = None) -> None:
        pass

    def get_records(self) -> list:
        return self.records

    def __str__(self) -> str:
        return self.name


class ConsoleIORecorder(BaseIORecorder):
    def __init__(self):
        super().__init__()
        self.name = "ConsoleIORecorder"

    def record(self, input_data: Any, output_data: Any, metadata: Optional[Dict] = None) -> None:
        timestamp = datetime.now().isoformat()
        record = {
            "timestamp": timestamp,
            "input": input_data,
            "output": output_data,
            "metadata": metadata or {},
        }
        self.records.append(record)
        print(f"[{self.name}] {timestamp} - 记录交互：输入={str(input_data)[:100]}..., 输出={str(output_data)[:100]}...")


class BaseAggregationService(ABC):
    def __init__(self):
        self.name = "BaseAggregationService"
        self.aggregated_data = []

    @abstractmethod
    def aggregate(self, response_data: Any) -> Any:
        pass

    @abstractmethod
    def get_result(self) -> Any:
        pass

    def __str__(self) -> str:
        return self.name


class SimpleAggregationService(BaseAggregationService):
    def __init__(self):
        super().__init__()
        self.name = "SimpleAggregationService"
        self.chunks = []

    def aggregate(self, response_data: Any) -> None:
        self.chunks.append(response_data)
        print(f"[{self.name}] 聚合数据块：{str(response_data)[:100]}...")

    def get_result(self) -> str:
        result = "".join(str(chunk) for chunk in self.chunks)
        self.aggregated_data.append(result)
        return result

    def reset(self) -> None:
        self.chunks = []


class QwenService:
    def __init__(
        self,
        model_config: ModelConfig,
        output_service: Optional[BaseOutputService] = None,
        io_recorder: Optional[BaseIORecorder] = None,
        aggregation_service: Optional[BaseAggregationService] = None,
    ):
        self.config = model_config
        self.output_service = output_service or ConsoleOutputService()
        self.io_recorder = io_recorder or ConsoleIORecorder()
        self.aggregation_service = aggregation_service or SimpleAggregationService()

    def send_request(self, input_data: Dict[str, Any]) -> Generator[Any, None, None]:
        headers = {
            "Authorization": f"Bearer {self.config.api_key}",
            "Content-Type": "application/json",
        }

        payload = {
            "model": self.config.model_name,
            "messages": input_data.get("messages", []),
            "temperature": self.config.temperature,
            "max_tokens": self.config.max_tokens,
            "stream": self.config.stream,
        }

        if self.config.extra_params:
            payload.update(self.config.extra_params)

        print(f"[QwenService] 发送请求到：{self.config.api_endpoint}")
        print(f"[QwenService] 模型：{self.config.model_name}")

        try:
            if self.config.stream:
                response = requests.post(
                    self.config.api_endpoint,
                    headers=headers,
                    json=payload,
                    stream=True,
                    timeout=self.config.timeout,
                )
                response.raise_for_status()

                for line in response.iter_lines():
                    if line:
                        line_str = line.decode("utf-8")
                        if line_str.startswith("data: "):
                            data_str = line_str[6:]
                            if data_str.strip() == "[DONE]":
                                break
                            try:
                                data = json.loads(data_str)
                                self.output_service.output(data)
                                yield data
                            except json.JSONDecodeError:
                                continue
            else:
                response = requests.post(
                    self.config.api_endpoint,
                    headers=headers,
                    json=payload,
                    timeout=self.config.timeout,
                )
                response.raise_for_status()
                data = response.json()
                self.output_service.output(data)
                yield data

        except requests.exceptions.RequestException as e:
            error_msg = f"请求失败：{str(e)}"
            print(f"[QwenService] {error_msg}")
            raise

    def call(
        self, input_data: Dict[str, Any]
    ) -> Dict[str, Any]:
        start_time = time.time()

        print(f"[QwenService] 开始调用大模型服务")
        print(f"[QwenService] 输入数据：{str(input_data)[:200]}...")

        all_responses = []
        try:
            for response_chunk in self.send_request(input_data):
                if self.aggregation_service:
                    self.aggregation_service.aggregate(response_chunk)
                all_responses.append(response_chunk)

            final_result = (
                self.aggregation_service.get_result()
                if self.aggregation_service
                else all_responses
            )

            end_time = time.time()
            duration = end_time - start_time

            metadata = {
                "start_time": datetime.fromtimestamp(start_time).isoformat(),
                "end_time": datetime.fromtimestamp(end_time).isoformat(),
                "duration_seconds": duration,
                "model": self.config.model_name,
            }

            if self.io_recorder:
                self.io_recorder.record(
                    input_data=input_data,
                    output_data=final_result,
                    metadata=metadata,
                )

            print(f"[QwenService] 调用完成，耗时：{duration:.2f}秒")

            return {
                "success": True,
                "result": final_result,
                "metadata": metadata,
            }

        except Exception as e:
            error_result = {
                "success": False,
                "error": str(e),
                "timestamp": datetime.now().isoformat(),
            }
            print(f"[QwenService] 调用失败：{str(e)}")

            if self.io_recorder:
                self.io_recorder.record(
                    input_data=input_data,
                    output_data=error_result,
                    metadata={"error": True},
                )

            return error_result


def create_qwen_service(
    model_config: ModelConfig,
    use_console_output: bool = True,
    use_console_recorder: bool = True,
    use_simple_aggregation: bool = True,
) -> QwenService:
    output_service = ConsoleOutputService() if use_console_output else None
    io_recorder = ConsoleIORecorder() if use_console_recorder else None
    aggregation_service = (
        SimpleAggregationService() if use_simple_aggregation else None
    )

    return QwenService(
        model_config=model_config,
        output_service=output_service,
        io_recorder=io_recorder,
        aggregation_service=aggregation_service,
    )


if __name__ == "__main__":
    config = ModelConfig(
        api_endpoint="https://dashscope.aliyuncs.com/api/v1/services/aigc/text-generation/generation",
        api_key="your-api-key-here",
        model_name="qwen-max",
    )

    service = create_qwen_service(config)

    test_input = {
        "messages": [
            {"role": "system", "content": "你是一个有帮助的助手。"},
            {"role": "user", "content": "你好，请介绍一下你自己。"},
        ]
    }

    result = service.call(test_input)
    print(f"\n最终结果：{result}")
