        )

    def load_from_file(self) -> ModelConfig:
        if not os.path.exists(self.config_path):
            raise FileNotFoundError(f"配置文件不存在：{self.config_path}")

        with open(self.config_path, "r", encoding="utf-8") as f:
            config_data = json.load(f)

        return ModelConfig(**config_data)

    def load_from_env(self) -> ModelConfig:
        required_vars = ["LLM_API_ENDPOINT", "LLM_API_KEY"]
        for var in required_vars:
            if var not in os.environ:
                raise EnvironmentError(f"环境变量 {var} 未设置")

        return ModelConfig(
            api_endpoint=os.environ["LLM_API_ENDPOINT"],
            api_key=os.environ["LLM_API_KEY"],
