        )

    def load_from_dict(self, config_dict: Dict[str, Any]) -> ModelConfig:
        return ModelConfig(**config_dict)

    def load(
        self, source: str = "auto", config_dict: Optional[Dict[str, Any]] = None
    ) -> ModelConfig:
        if source == "file" or (source == "auto" and os.path.exists(self.config_path)):
            return self.load_from_file()
        elif source == "env" or (source == "auto" and config_dict is None):
            return self.load_from_env()
        elif source == "dict" or config_dict is not None:
            if config_dict is None:
                raise ValueError("config_dict 不能为空")
            return self.load_from_dict(config_dict)
        else:
            raise ValueError(f"未知的配置来源：{source}")


def get_model_config(
    source: str = "auto", config_dict: Optional[Dict[str, Any]] = None
) -> ModelConfig:
    loader = ModelConfigLoader()
    return loader.load(source=source, config_dict=config_dict)
